import re
def measure(output_files, reference_files):
    for f in output_files:
        text = f.read_text()
        sentences = [s.strip() for s in re.split(r'(?<=[.?!])\s+', text) if s.strip()]
        sentences = [s for s in sentences if not s.startswith('#') and not s.startswith('---') and not s.startswith('[^')]
        if not sentences:
            return {'value': 0.0, 'detail': 'No narrative sentences'}
        cited = sum(1 for s in sentences if re.search(r'\[\^[^\]]+\]', s))
        ratio = cited / len(sentences)
        return {'value': round(ratio, 3), 'detail': f'{cited}/{len(sentences)} sentences cited'}

import re
def measure(output_files, reference_files):
    required_h1 = {'규제 환경 요약','첨가물정보제출','분석결과제출','제품 규격 및 준수사항'}
    allowed_titles = required_h1 | {'규제 요건','신규제출','변경제출','정기제출','제출 시기','제출 대상 및 자료','제출 방법','담배 원료 (tobacco)','담배 외 원료 및 재료 (other than tobacco)','담배 제품 (tobacco products)','각주'}
    for f in output_files:
        text = f.read_text()
        lines = text.splitlines()
        issues = []
        footnote_defs = []
        canonical_empty = '해당 없음 (근거 문서 없음)'
        weak_empty_patterns = [r'별도 .* 확인되지 않는다', r'언급되지 않는다', r'규정은 확인되지 않는다', r'명시적으로 확인되지 않는다']
        seen_h1 = set()
        for i, line in enumerate(lines, 1):
            stripped = line.lstrip()
            heading = re.match(r'^(#{2,4})\s+(.*)$', stripped)
            if heading:
                title = heading.group(2).strip()
                if title not in allowed_titles:
                    issues.append(f'L{i}: off-contract heading {title}')
                if heading.group(1) == '##':
                    seen_h1.add(title)
            if stripped.startswith('> [!'):
                issues.append(f'L{i}: callout not allowed')
            if re.match(r'^(?:-|\d+\.)\s+#{1,6}\s+', stripped):
                issues.append(f'L{i}: heading marker inside list item')
            if re.match(r'^\d+\.\s+\*\*', stripped):
                issues.append(f'L{i}: ordered list used as label')
            if re.match(r'^[-*]?\s*(법규|실무|제출 범위|요약):\s*$', stripped):
                issues.append(f'L{i}: pseudo-section label')
            if any(re.search(p, stripped) for p in weak_empty_patterns) and canonical_empty not in stripped:
                issues.append(f'L{i}: non-canonical empty text')
            if stripped.startswith(('-', '*', '+')) or re.match(r'\d+\.', stripped):
                indent = len(line) - len(stripped)
                if indent > 0 and indent % 4 != 0:
                    issues.append(f'L{i}: indent {indent}')
                if '\t' in line:
                    issues.append(f'L{i}: tab')
            if re.match(r'\[\^[^\]]+\]:', stripped):
                footnote_defs.append(stripped)
                if not re.search(r'\[\[(.+?)\]\]', stripped):
                    issues.append(f'L{i}: footnote not wikilink format')
        missing_h1 = sorted(required_h1 - seen_h1)
        for title in missing_h1:
            issues.append(f'missing required heading: {title}')
        total_checkable = max(1, sum(1 for l in lines if l.startswith('#')) + sum(1 for l in lines if l.lstrip().startswith(('-', '*', '+')) or re.match(r'\s*\d+\.', l)) + len(footnote_defs) + len(required_h1))
        error_rate = len(issues) / total_checkable
        score = max(0, 1.0 - error_rate)
        detail = f'{len(issues)} issues / {total_checkable} items'
        if issues:
            detail += f" (first 5: {'; '.join(issues[:5])})"
        return {'value': round(score, 3), 'detail': detail}

